var e=[{id:`L2_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`으읏…….`,JPN:`ううっ……`,ENG:`Ugh...`,TWN:`唔呃……`},stage:{bg:`SCHOOL_SPRING`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`NAIEL_SCHOOL_NPC_NULL`,text:{KOREA:`내, 내가… 벴어?!`,JPN:`わ、私が……斬った！？`,ENG:`I-I... slashed her?!`,TWN:`我…砍到了？！`},stage:{bg:`SCHOOL_SPRING`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`NAIEL_SCHOOL_NPC_NULL`,face:`UNIT_SURPRISE`}}}},{id:`L8_1`,type:`dialog`,speaker:`HANDGUN_ACADEMY_NULL_NULL`,text:{KOREA:`거기, 잠깐 중지!`,JPN:`そこ、ちょっと中止！`,ENG:`Hey, stop!`,TWN:`你們，暫停！`},stage:{bg:`SCHOOL_SPRING`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HANDGUN_ACADEMY_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}},sfx:`FX_CUTSCEN_WHISTLE_02`},{id:`L9_1`,type:`dialog`,speaker:`HANDGUN_ACADEMY_NULL_NULL`,text:{KOREA:`시엘 양! 상태는 어때? 괜찮아?`,JPN:`シエルさん！　大丈夫？　負傷したの？`,ENG:`Ciel! Are you all right?`,TWN:`希爾同學！你還好嗎？`},stage:{bg:`SCHOOL_SPRING`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HANDGUN_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`…빈틈을 보이고 말았구려. 본인의 패배요.`,JPN:`……隙を見せてしまいました。自分の負けです。`,ENG:`..I let my guard down in battle. I admit defeat.`,TWN:`…露出破綻了，在下認輸。`},stage:{bg:`SCHOOL_SPRING`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`혹시 이 근처에 상처를 치료를 받을 만한 곳이 있소?`,JPN:`近くに傷を治療できるところがありますか？`,ENG:`Is there a place where I can tend to my wounds?`,TWN:`這附近有可以治療的地方嗎？`},stage:{bg:`SCHOOL_SPRING`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`HANDGUN_ACADEMY_NULL_NULL`,text:{KOREA:`으음, 어쩌지? 양호실 선생님이 지금 외근 중이라서…`,JPN:`どうしよう、困ったわね。保健室の先生は今外勤中なんだよ……`,ENG:`Mm... Bad timing. The school nurse is out at the moment...`,TWN:`呃，怎麼辦？保健室老師剛好外出…`},stage:{bg:`SCHOOL_SPRING`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HANDGUN_ACADEMY_NULL_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`PRESIDENT_SCHOOL_NULL_NULL`,text:{KOREA:`제가 도와드리죠.`,JPN:`私が手伝いましょう。`,ENG:`I will help you.`,TWN:`我來幫你吧。`},stage:{bg:`SCHOOL_SPRING`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HANDGUN_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`그대는…?`,JPN:`貴殿は……？`,ENG:`You are...?`,TWN:`你是…？`},stage:{bg:`SCHOOL_SPRING`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`HANDGUN_ACADEMY_NULL_NULL`,text:{KOREA:`앗, 학생회장!`,JPN:`あっ、生徒会長！`,ENG:`Oh, it's the Student President!`,TWN:`喔，學生會長！`},stage:{bg:`SCHOOL_SPRING`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`HANDGUN_ACADEMY_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`PRESIDENT_SCHOOL_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L21_1`,type:`dialog`,speaker:`HANDGUN_ACADEMY_NULL_NULL`,text:{KOREA:`마침 잘 됐다. 그럼 부탁할게.`,JPN:`助かるわ。じゃあ、お願いね。`,ENG:`Good timing. Then, I'll leave her with you.`,TWN:`你來得正好，那就麻煩你囉。`},stage:{bg:`SCHOOL_SPRING`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`HANDGUN_ACADEMY_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`PRESIDENT_SCHOOL_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L22_1`,type:`dialog`,speaker:`PRESIDENT_SCHOOL_NULL_NULL`,text:{KOREA:`절 따라오세요, 시엘 양.`,JPN:`シエルさん、私について来てください。`,ENG:`Follow me, Ciel.`,TWN:`希爾同學，請跟我來。`},stage:{bg:`SCHOOL_SPRING`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`HANDGUN_ACADEMY_NULL_NULL`,face:`UNIT_LAUGH`},C:null,R:{char_id:`PRESIDENT_SCHOOL_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L24_1`,type:`dialog`,speaker:`CIEL_ACADEMY_NULL_NULL`,text:{KOREA:`낭자가… 학생회장?`,JPN:`貴殿が……生徒会長？`,ENG:`You... are the Student President?`,TWN:`姑娘你是… 學生會長？`},stage:{bg:`SCHOOL_SPRING`,bgm:`CUTSCENE_TALK_01`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CIEL_ACADEMY_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}}];export{e as default};